import json
import re
from collections import Counter

# Try to find the correct file path
# The clinical data should be in a file, let's check what files are available
import os
print("Files in /tmp:")
for f in os.listdir('/tmp'):
    if f.startswith('data_') and f.endswith('.json'):
        print(f)

# Let's try the most recent clinical data file
clinical_file = '/tmp/data_jz9x0w4j.json'
if os.path.exists(clinical_file):
    with open(clinical_file, 'r') as f:
        clinical_data = json.load(f)

    print(f"\nLoaded {len(clinical_data)} clinical records")

    # Extract female BRCA patients with histological types
    female_brca = {}
    for record in clinical_data:
        desc = record.get('Patient_description', '').lower()
        hist_type = record.get('histological_type')

        # Check if female breast cancer patient
        if 'female' in desc and 'breast' in desc:
            # Extract patient barcode
            match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', record.get('Patient_description', ''))
            if match:
                barcode = match.group()
                # Only include if histological type is known and not None/Null
                if hist_type and hist_type != 'None' and hist_type.strip():
                    female_brca[barcode] = hist_type.strip()

    print(f"\nFemale BRCA patients with known histology: {len(female_brca)}")

    if female_brca:
        print("\nHistological type distribution:")
        hist_counts = Counter(female_brca.values())
        for hist, count in hist_counts.most_common():
            print(f"  {hist}: {count}")

        # Save results for later use
        __result__ = {
            'female_brca_patients': female_brca,
            'hist_counts': dict(hist_counts),
            'total_patients': len(female_brca)
        }
    else:
        __result__ = {'error': 'No matching patients found'}
else:
    print(f"File not found: {clinical_file}")
    __result__ = {'error': 'File not found'}

print('__RESULT__:')
print(json.dumps(__result__))

