import json, re
from collections import Counter

# Load data files
clinical_file = '/tmp/data_94g6r4z9.json'
mutation_file = '/tmp/data_k1b7o24f.json'

with open(clinical_file) as f:
    clinical_data = json.load(f)

with open(mutation_file) as f:
    mutation_data = json.load(f)

# Process clinical data - extract female BRCA patients
female_brca_patients = {}
for record in clinical_data:
    desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type')

    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if match:
        barcode = match.group()
        if hist_type and hist_type != 'None' and hist_type.strip():
            female_brca_patients[barcode] = hist_type.strip()

# Get CDH1 mutation patients
mutation_patients = set(r['ParticipantBarcode'] for r in mutation_data)

# Build contingency table
contingency = {}
hist_counts = Counter(female_brca_patients.values())

for hist in hist_counts:
    contingency[hist] = {'mutation': 0, 'no_mutation': 0, 'total': 0}

for patient, hist in female_brca_patients.items():
    if patient in mutation_patients:
        contingency[hist]['mutation'] += 1
    else:
        contingency[hist]['no_mutation'] += 1
    contingency[hist]['total'] += 1

# Filter categories with marginal totals > 10
filtered = {h: c for h, c in contingency.items() if c['total'] > 10}

# Calculate chi-square
chi2 = 0.0
total_mut = sum(c['mutation'] for c in filtered.values())
total_no_mut = sum(c['no_mutation'] for c in filtered.values())
total_filtered = total_mut + total_no_mut

for hist, counts in filtered.items():
    exp_mut = (counts['total'] * total_mut) / total_filtered
    exp_no_mut = (counts['total'] * total_no_mut) / total_filtered

    if exp_mut > 0:
        chi2 += ((counts['mutation'] - exp_mut) ** 2) / exp_mut
    if exp_no_mut > 0:
        chi2 += ((counts['no_mutation'] - exp_no_mut) ** 2) / exp_no_mut

result = {
    'chi_square_statistic': chi2,
    'contingency_table': filtered,
    'total_patients': total_filtered
}

print('__RESULT__:')
print(json.dumps(result))

