# Try to find the correct paths
all_files = []
for root, dirs, files in os.walk('/mnt'):
    for filename in files:
        if filename.endswith('.json'):
            filepath = os.path.join(root, filename)
            all_files.append(filepath)
            if len(all_files) >= 20:
                break
    if len(all_files) >= 20:
        break

print('First 20 JSON files found:')
for f in all_files[:20]:
    print(f)

# Also check for clinical and mutation data patterns
clinical_candidates = []
mutation_candidates = []

for root, dirs, files in os.walk('/mnt'):
    for filename in files:
        if 'clinical' in filename.lower() and filename.endswith('.json'):
            clinical_candidates.append(os.path.join(root, filename))
        elif 'mutation' in filename.lower() and filename.endswith('.json'):
            mutation_candidates.append(os.path.join(root, filename))

print('\nClinical data candidates:', clinical_candidates)
print('Mutation data candidates:', mutation_candidates)

result = {
    'clinical_candidates': clinical_candidates,
    'mutation_candidates': mutation_candidates,
    'total_files_found': len(all_files)
}

print('__RESULT__:')
print(json.dumps(result))

